"use client";

import { useState } from "react";
import Link from "next/link";
import { DataTable, Column } from "@/components/tables/data-table";
import { useContactRequests } from "@/hooks/use-contact-requests";
import type { ContactRequest } from "@/types";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { useRouter } from "next/navigation";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { formatDate } from "@/lib/utils";
import { ExternalLink, Mail } from "lucide-react";

export default function ContactPage() {
  const [page, setPage] = useState(1);
  const { data, isLoading } = useContactRequests({ page });
  const router = useRouter();

  const [attachmentPreview, setAttachmentPreview] = useState<{
    url: string;
    filename?: string;
    mimetype?: string;
  } | null>(null);

  const columns: Column<ContactRequest>[] = [
    {
      key: "user",
      header: "User",
      cell: (req) => (
        req.user?.id ? (
          <Link
            href={`/users/${req.user.id}`}
            className="text-sm text-blue-600 hover:underline font-medium"
            onClick={(e) => e.stopPropagation()}
          >
            {req.user?.fullName ?? req.user?.email ?? `#${req.user.id}`}
          </Link>
        ) : (
          <span className="text-sm text-muted-foreground">
            {req.user?.fullName ?? req.user?.email ?? "Unknown"}
          </span>
        )
      ),
    },
    {
      key: "subject",
      header: "Subject",
      cell: (req) => (
        <p className="text-sm font-medium truncate" title={req.subject}>
          {req.subject}
        </p>
      ),
    },
    {
      key: "message",
      header: "Message",
      cell: (req) => (
        <p className="text-sm text-muted-foreground max-w-xs truncate" title={req.message}>
          {req.message}
        </p>
      ),
    },
    {
      key: "cc",
      header: "CC",
      cell: (req) =>
        req.cc ? (
          <span className="text-sm text-muted-foreground">{req.cc}</span>
        ) : (
          <span className="text-sm text-muted-foreground italic">—</span>
        ),
    },
    {
      key: "attachmentFile",
      header: "Attachment",
      cell: (req) => {
        const url = req.attachmentFile?.url;
        return url ? (
          req.attachmentFile?.mimetype?.startsWith("image/") ? (
            // eslint-disable-next-line @next/next/no-img-element
            <img
              src={url}
              alt={req.attachmentFile?.filename ?? "attachment"}
              className="w-12 h-12 object-cover rounded border cursor-pointer hover:opacity-90"
              onClick={(e) => {
                e.stopPropagation();
                setAttachmentPreview({
                  url,
                  filename: req.attachmentFile?.filename,
                  mimetype: req.attachmentFile?.mimetype,
                });
              }}
            />
          ) : (
            <Button
              variant="ghost"
              size="sm"
              className="gap-2"
              onClick={(e) => {
                e.stopPropagation();
                setAttachmentPreview({
                  url,
                  filename: req.attachmentFile?.filename,
                  mimetype: req.attachmentFile?.mimetype,
                });
              }}
            >
              <ExternalLink className="h-4 w-4" />
              Preview
            </Button>
          )
        ) : (
          <Badge variant="outline">No file</Badge>
        );
      },
    },
    {
      key: "createdAt",
      header: "Date",
      cell: (req) => (
        <span className="text-sm text-muted-foreground">
          {formatDate(req.createdAt)}
        </span>
      ),
    },
  ];

  return (
    <div className="space-y-6">
      <div className="flex items-center gap-3">
        <div className="p-2 rounded-lg bg-indigo-100">
          <Mail className="h-5 w-5 text-indigo-600" />
        </div>
        <div>
          <h1 className="text-2xl font-bold">Contact Us</h1>
          <p className="text-muted-foreground text-sm">
            View all contact messages
            {data?.total ? ` · ${data.total} total` : ""}
          </p>
        </div>
      </div>

      <DataTable
        columns={columns}
        data={(data?.data ?? []) as ContactRequest[]}
        isLoading={isLoading}
        searchKey="subject"
        searchPlaceholder="Search by subject..."
        page={page}
        totalPages={data?.totalPages}
        onPageChange={setPage}
      />
    </div>
  );
}

